#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        int K;
        scanf("%lld %d", &N, &K);
        if (K == 0) {
            puts("Off");
        } else {
            if (N % 4 == 0) puts("On");
            else puts("Ambiguous");
        }
    }
    return 0;
}

